void generate(int n) {
    static string s = "";

    // Base case
    if (s.length() == n) {
        cout << s << endl;
        return;
    }

    // Try adding '0'
    s.push_back('0');
    generate(n);
    s.pop_back();

    // Try adding '1' only if last character is not '1'
    if (s.empty() || s.back() == '0') {
        s.push_back('1');
        generate(n);
        s.pop_back();
    }
}

code.C:
void generate(int n) {
    static char s[21];   // n ≤ 20
    static int len = 0;

    // Base case
    if (len == n) {
        s[len] = '\0';
        printf("%s\n", s);
        return;
    }

    // Always try adding '0'
    s[len++] = '0';
    generate(n);
    len--;

    // Try adding '1' only if previous character is not '1'
    if (len == 0 || s[len - 1] == '0') {
        s[len++] = '1';
        generate(n);
        len--;
    }
}

code.Java:
public static void generate(int n) {
    StringBuilder sb = new StringBuilder();

    backtrack(n, sb);
}

private static void backtrack(int n, StringBuilder sb) {
    // Base case
    if (sb.length() == n) {
        System.out.println(sb.toString());
        return;
    }

    // Always try adding '0'
    sb.append('0');
    backtrack(n, sb);
    sb.deleteCharAt(sb.length() - 1);

    // Try adding '1' only if previous character is not '1'
    if (sb.length() == 0 || sb.charAt(sb.length() - 1) == '0') {
        sb.append('1');
        backtrack(n, sb);
        sb.deleteCharAt(sb.length() - 1);
    }
}

