function generate(n) {
    const arr = [];

    function backtrack() {
        // Base case
        if (arr.length === n) {
            console.log(arr.join(""));
            return;
        }

        // Always try adding '0'
        arr.push('0');
        backtrack();
        arr.pop();

        // Try adding '1' only if previous character is not '1'
        if (arr.length === 0 || arr[arr.length - 1] === '0') {
            arr.push('1');
            backtrack();
            arr.pop();
        }
    }

    backtrack();
}
